"""
Verify the Modal Volume contents
"""
import modal
import os

app = modal.App("verify-volume")

volume = modal.Volume.from_name("modal-nfs-etl-pipeline-vol")

@app.function(
    image=modal.Image.debian_slim().pip_install("pandas"),
    volumes={"/shared": volume},
)
def list_files():
    """List files in the shared volume"""
    import os

    shared_path = "/shared"
    files = []

    if os.path.exists(shared_path):
        for root, dirs, filenames in os.walk(shared_path):
            for filename in filenames:
                filepath = os.path.join(root, filename)
                size = os.path.getsize(filepath)
                files.append({
                    "path": filepath,
                    "size": size,
                })

    return files

@app.function(
    image=modal.Image.debian_slim().pip_install("pandas"),
    volumes={"/shared": volume},
)
def read_file_stats(filepath):
    """Read and return file statistics"""
    import os

    if os.path.exists(filepath):
        return {
            "exists": True,
            "size": os.path.getsize(filepath),
            "path": filepath,
        }
    else:
        return {
            "exists": False,
            "path": filepath,
        }

@app.local_entrypoint()
def main():
    print("Modal Volume Contents:")
    print("=" * 60)

    files = list_files.remote()

    expected_files = [
        "/shared/raw_data.csv",
        "/shared/transformed_data.csv",
        "/shared/final_report.json",
    ]

    print(f"\nFound {len(files)} file(s) in volume:")
    for file_info in files:
        print(f"  - {file_info['path']} ({file_info['size']} bytes)")

    print("\nExpected files verification:")
    for filepath in expected_files:
        stats = read_file_stats.remote(filepath)
        if stats["exists"]:
            print(f"  ✓ {filepath} - {stats['size']} bytes")
        else:
            print(f"  ✗ {filepath} - NOT FOUND")

    print("=" * 60)

